light.aceEditor:
.ace_editor {
   border: 1px solid #C1C7DC !important;
   border-radius: 0;
 }

 .ace-graylog {
   background-color: #fff;
   color: #06050F;

   &.ace_multiselect .ace_selection.ace_start {
     box-shadow: 0 0 3px 0 #fff;
   }

   .ace_gutter {
     background: #CAC8D7;
     color: #06050F;
   }

   .ace_print-margin {
     width: 1px;
     background: #FAF9FF;
   }

   .ace_cursor {
     border-color: #252D47;
   }

   .ace_marker-layer {
     .ace_selection {
       background: Highlight;
     }

     .ace_step {
       background: rgb(255 255 0);
     }

     .ace_bracket {
       margin: -1px 0 0 -1px;
       border: 1px solid #b6b9c2;
     }

     .ace_selected-word {
       border: 1px solid #9ea2ad;
       background: transparent;
     }

     .ace_active-line {
       background: #FAF9FF;
     }
   }

   .ace_gutter-active-line {
     background-color: #FAF9FF;
   }

   .ace_invisible {
     color: #b6b9c2;
   }

   .ace_keyword,
   .ace_meta,
   .ace_storage,
   .ace_storage.ace_type,
   .ace_support.ace_type {
     color: #1877EF;
   }

   .ace_keyword.ace_operator {
     color: #006B8F;
   }

   .ace_constant.ace_character,
   .ace_constant.ace_language,
   .ace_constant.ace_numeric,
   .ace_keyword.ace_other.ace_unit,
   .ace_support.ace_constant,
   .ace_variable.ace_parameter {
     color: #083772;
   }

   .ace_constant.ace_other {
     color: #0D0A1F;
   }

   .ace_invalid {
     color: #fff;
     background-color: #FE6E6D;
   }

   .ace_invalid.ace_deprecated {
     color: #fff;
     background-color: #1877EF;
   }

   .ace_fold {
     background-color: #03C2FF;
     border-color: #06050F;
   }

   .ace_entity.ace_name.ace_function,
   .ace_support.ace_function,
   .ace_variable {
     color: #03C2FF;
   }

   .ace_support.ace_class,
   .ace_support.ace_type {
     color: #7A6000;
   }

   .ace_heading,
   .ace_markup.ace_heading,
   .ace_string {
     color: #128057;
   }

   .ace_entity.ace_name.ace_tag,
   .ace_entity.ace_other.ace_attribute-name,
   .ace_meta.ace_tag,
   .ace_string.ace_regexp,
   .ace_variable {
     color: #FE6E6D;
   }

   .ace_comment {
     color: rgba(37,45,71,0.6);
   }

   .ace_tooltip {
     background-color: #EEEDF6;
     padding: 4px;
     padding-left: 0;
     line-height: 1.5;

     .ace_icon {
       margin-right: 3px;
     }
   }
 }

